# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.

Allowlist valid hosts/paths and validate universal link parameters before navigation or privileged actions.
# Category: insecure_universal_links

import UIKit
import Foundation

class UniversalLinkHandler: NSObject, WKNavigationDelegate {
    let webView = WKWebView()
    
    override init() {
        super.init()
        
        // Allowlist valid hosts and paths for password reset links
        let allowlist = ["myapp.com", "/reset-password"]
        
        // Validate universal link parameters before navigation or privileged actions
        webView.navigationDelegate = self
    }
    
    func webView(_ webView: WKWebView, didReceive challenge: URLAuthenticationChallenge) {
        guard let url = challenge.protectionSpace.host else { return }
        
        // Check if the host is in the allowlist
        if !allowlist.contains(url) {
            // Reject the challenge if the host is not in the allowlist
            challenge.sender?.rejectProtectionSpaceAndContinue(with: nil)
            return
        }
        
        // Check if the path is valid for password reset links
        if !allowlist.contains(challenge.protectionSpace.path) {
            // Reject the challenge if the path is not valid for password reset links
            challenge.sender?.rejectProtectionSpaceAndContinue(with: nil)
            return
        }
        
        // Accept the challenge and navigate to the password reset screen with the token
        challenge.sender?.use(URLCredential(trust: challenge.protectionSpace.serverTrust!), for: challenge)
    }
}